import * as React from 'react';
/**
 * 选择器弹层空状态子组件
 * - 包含了空状态逻辑
 * - 包含了弹层的边框样式
 * - 样式写在 select 里面，select、tree-select、cascader 共享
 */
export declare const SelectOverlayContainer: ({ className, optionsLength, filteredOptionsLength, menu, }: {
    className?: string;
    /** 过滤前的 options 个数 */
    optionsLength: number;
    /** 过滤后的菜单项目个数，如果是 0 则会走空状态逻辑 */
    filteredOptionsLength: number;
    /** menu 是 overlay 不空的时候展示的菜单组件 */
    menu: React.ReactElement;
}) => React.JSX.Element | null;
